import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import './Practice.css';

function Practice() {
  const navigate = useNavigate();
  const [step, setStep] = useState('selection'); // selection, interview
  const [selectedRole, setSelectedRole] = useState(null);
  const [sessionId, setSessionId] = useState(null);
  const [messages, setMessages] = useState([]);
  const [currentAnswer, setCurrentAnswer] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [timeLimit, setTimeLimit] = useState(30); // minutes
  const [timeRemaining, setTimeRemaining] = useState(null);
  const [timerInterval, setTimerInterval] = useState(null);

  const roles = [
    {
      id: 'software-engineer',
      name: 'Software Engineer',
      icon: '💻',
      description: 'General software engineering questions covering algorithms, system design, and coding',
      questions: 15
    },
    {
      id: 'data-scientist',
      name: 'Data Scientist',
      icon: '📊',
      description: 'Data science and machine learning focused questions',
      questions: 12
    },
    {
      id: 'product-manager',
      name: 'Product Manager',
      icon: '📱',
      description: 'Product management and strategy questions',
      questions: 10
    },
    {
      id: 'frontend-developer',
      name: 'Frontend Developer',
      icon: '🎨',
      description: 'Frontend development and UI/UX questions',
      questions: 14
    },
    {
      id: 'backend-developer',
      name: 'Backend Developer',
      icon: '⚙️',
      description: 'Backend development and API design questions',
      questions: 13
    },
    {
      id: 'devops-engineer',
      name: 'DevOps Engineer',
      icon: '🔧',
      description: 'DevOps, CI/CD, and infrastructure questions',
      questions: 11
    }
  ];

  // Prevent tab switching during interview
  useEffect(() => {
    if (step === 'interview') {
      const handleBeforeUnload = (e) => {
        e.preventDefault();
        e.returnValue = 'Interview in progress. Are you sure you want to leave?';
        return e.returnValue;
      };

      const handlePopState = (e) => {
        if (window.confirm('Interview in progress. Are you sure you want to leave?')) {
          return true;
        } else {
          window.history.pushState(null, '', window.location.pathname);
          e.preventDefault();
          return false;
        }
      };

      window.addEventListener('beforeunload', handleBeforeUnload);
      window.history.pushState(null, '', window.location.pathname);
      window.addEventListener('popstate', handlePopState);

      return () => {
        window.removeEventListener('beforeunload', handleBeforeUnload);
        window.removeEventListener('popstate', handlePopState);
      };
    }
  }, [step]);

  // Detect tab visibility change
  useEffect(() => {
    if (step === 'interview') {
      const handleVisibilityChange = () => {
        if (document.hidden) {
          alert('⚠️ Please stay on this tab during the interview!');
        }
      };

      document.addEventListener('visibilitychange', handleVisibilityChange);

      return () => {
        document.removeEventListener('visibilitychange', handleVisibilityChange);
      };
    }
  }, [step]);

  // Timer management
  useEffect(() => {
    if (step === 'interview' && timeRemaining !== null) {
      const interval = setInterval(() => {
        setTimeRemaining(prev => {
          if (prev <= 1) {
            clearInterval(interval);
            handleTimeUp();
            return 0;
          }

          // Warnings at specific times
          if (prev === 300) { // 5 minutes
            alert('⏰ 5 minutes remaining!');
          } else if (prev === 60) { // 1 minute
            alert('⏰ 1 minute remaining!');
          }

          return prev - 1;
        });
      }, 1000);

      setTimerInterval(interval);

      return () => {
        if (interval) clearInterval(interval);
      };
    }
  }, [step, timeRemaining]);

  const handleTimeUp = async () => {
    alert('⏰ Time is up! Your interview will be completed automatically.');
    await handleCompleteInterview();
  };

  const formatTime = (seconds) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const getTimeColor = () => {
    if (!timeRemaining) return '#48bb78';
    const percentage = (timeRemaining / (timeLimit * 60)) * 100;
    if (percentage > 50) return '#48bb78'; // green
    if (percentage > 25) return '#ed8936'; // orange
    return '#f56565'; // red
  };

  const handleStartPractice = async (role) => {
    setSelectedRole(role);
    setLoading(true);
    setError('');

    try {
      const token = localStorage.getItem('token');

      if (!token) {
        setError('Please sign in to start practice interview');
        navigate('/signin');
        return;
      }

      const response = await fetch('http://localhost:5000/api/practice/start', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ roleId: role.id })
      });

      const data = await response.json();

      if (data.success) {
        setSessionId(data.session.id);
        setMessages([{
          type: 'ai',
          text: data.session.question
        }]);
        setTimeRemaining(timeLimit * 60); // Convert minutes to seconds
        setStep('interview');
      } else {
        setError(data.message || 'Failed to start practice interview');
      }
    } catch (error) {
      console.error('Start practice error:', error);
      setError('Network error. Please check your connection and try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleSendAnswer = async () => {
    if (!currentAnswer.trim() || loading) return;

    const userMessage = currentAnswer.trim();
    setCurrentAnswer('');
    setLoading(true);
    setError('');

    // Add user message to chat
    setMessages(prev => [...prev, {
      type: 'user',
      text: userMessage
    }]);

    try {
      const token = localStorage.getItem('token');
      const response = await fetch(`http://localhost:5000/api/interview/${sessionId}/answer`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ answer: userMessage })
      });

      const data = await response.json();

      if (data.success) {
        // Add AI response
        setMessages(prev => [...prev, {
          type: 'ai',
          text: data.question
        }]);
      } else {
        setError(data.message || 'Failed to get next question');
      }
    } catch (error) {
      console.error('Submit answer error:', error);
      setError('Network error. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleCompleteInterview = async () => {
    if (!sessionId || loading) return;

    const confirmed = window.confirm('Are you sure you want to complete this interview?');
    if (!confirmed) return;

    // Clear timer
    if (timerInterval) {
      clearInterval(timerInterval);
    }

    setLoading(true);
    setError('');

    try {
      const token = localStorage.getItem('token');
      const response = await fetch(`http://localhost:5000/api/interview/${sessionId}/complete`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        }
      });

      const data = await response.json();

      if (data.success) {
        // Redirect to dashboard to see results
        navigate('/dashboard');
      } else {
        setError(data.message || 'Failed to complete interview');
      }
    } catch (error) {
      console.error('Complete interview error:', error);
      setError('Failed to complete interview. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="practice-page">
      <div className="container">
        {error && <div className="alert alert-error">{error}</div>}

        {step === 'selection' && (
          <>
            <div className="practice-header fade-in">
              <h1>Practice Interviews</h1>
              <p>Choose a role to practice interview questions without uploading a resume</p>
            </div>

            <div className="roles-grid">
              {roles.map((role, index) => (
                <div 
                  key={role.id} 
                  className="role-card slide-in"
                  style={{animationDelay: `${index * 0.1}s`}}
                >
                  <div className="role-icon">{role.icon}</div>
                  <h3>{role.name}</h3>
                  <p>{role.description}</p>
                  <div className="role-meta">
                    <span className="question-count">📝 {role.questions} questions</span>
                  </div>
                  <button 
                    className="btn btn-primary btn-block"
                    onClick={() => handleStartPractice(role)}
                    disabled={loading}
                  >
                    {loading && selectedRole?.id === role.id ? 'Starting...' : 'Start Practice'}
                  </button>
                </div>
              ))}
            </div>

            <div className="practice-info">
              <div className="info-card">
                <h3>💡 How Practice Mode Works</h3>
                <ul>
                  <li>No resume required - jump right in</li>
                  <li>Role-specific questions tailored to the position</li>
                  <li>Get instant feedback on your answers</li>
                  <li>Track your progress across multiple sessions</li>
                  <li>Perfect for preparing for specific job roles</li>
                </ul>
              </div>

              <div className="info-card" style={{marginTop: '24px'}}>
                <h3>⏱️ Select Interview Duration</h3>
                <div className="time-options">
                  <button 
                    className={`time-option ${timeLimit === 30 ? 'active' : ''}`}
                    onClick={() => setTimeLimit(30)}
                  >
                    <div className="time-value">30</div>
                    <div className="time-label">Minutes</div>
                  </button>
                  <button 
                    className={`time-option ${timeLimit === 60 ? 'active' : ''}`}
                    onClick={() => setTimeLimit(60)}
                  >
                    <div className="time-value">60</div>
                    <div className="time-label">Minutes</div>
                  </button>
                  <button 
                    className={`time-option ${timeLimit === 120 ? 'active' : ''}`}
                    onClick={() => setTimeLimit(120)}
                  >
                    <div className="time-value">120</div>
                    <div className="time-label">Minutes</div>
                  </button>
                </div>
              </div>
            </div>
          </>
        )}

        {step === 'interview' && (
          <div className="interview-section fade-in">
            <div className="interview-warning">
              ⚠️ Interview in progress - Please do not switch tabs or close this window
            </div>
            <div className="interview-header">
              <div>
                <h1>Practice Interview: {selectedRole?.name}</h1>
                <p className="subtitle">Answer the questions to the best of your ability</p>
              </div>
              <div className="interview-controls">
                {timeRemaining !== null && (
                  <div className="timer" style={{ color: getTimeColor() }}>
                    <span className="timer-icon">⏱️</span>
                    <span className="timer-value">{formatTime(timeRemaining)}</span>
                  </div>
                )}
                <button 
                  onClick={handleCompleteInterview} 
                  className="btn btn-secondary"
                  disabled={loading || messages.length < 4}
                  title={messages.length < 4 ? 'Answer at least 2 questions before completing' : 'Complete interview'}
                >
                  Complete Interview
                </button>
              </div>
            </div>

            <div className="chat-container">
              {messages.map((msg, index) => (
                <div key={index} className={`message ${msg.type}-message`}>
                  <div className="message-avatar">
                    {msg.type === 'ai' ? '🤖' : '👤'}
                  </div>
                  <div className="message-content">
                    <p>{msg.text}</p>
                  </div>
                </div>
              ))}

              {loading && (
                <div className="message ai-message">
                  <div className="message-avatar">🤖</div>
                  <div className="message-content">
                    <p className="typing">Thinking...</p>
                  </div>
                </div>
              )}

              <div className="message-input-container">
                <textarea
                  className="message-input"
                  placeholder="Type your answer here..."
                  rows="4"
                  value={currentAnswer}
                  onChange={(e) => setCurrentAnswer(e.target.value)}
                  onKeyPress={(e) => {
                    if (e.key === 'Enter' && !e.shiftKey) {
                      e.preventDefault();
                      handleSendAnswer();
                    }
                  }}
                  disabled={loading}
                ></textarea>
                <button 
                  className="btn btn-primary" 
                  onClick={handleSendAnswer}
                  disabled={loading || !currentAnswer.trim()}
                >
                  {loading ? 'Sending...' : 'Send Answer'}
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default Practice;
